:root {
  --bg-card: #1a1a2e;
  --bg-art: #16213e;
  --bg-art-inner: #0f3460;
  --accent: #e94560;
  --accent-secondary: #f5a623;
  --text-primary: #ffffff;
  --text-secondary: #a0a8c0;
  --text-muted: #5a6080;
  --tag-bg: #2a2a4a;
  --tag-text: #a0a8c0;
  --progress-track: #2a2a4a;
  --progress-fill: #e94560;
  --progress-thumb: #ffffff;
  --ctrl-bg: #2a2a4a;
  --ctrl-text: #a0a8c0;
  --play-bg: #e94560;
  --play-text: #ffffff;
  --info-bg: #111128;
  --info-border: #2a2a4a;
  --art-circle: #e94560;
  --art-dot: #1a1a2e;
}

.player-card {
  background: var(--bg-card);
  border-radius: 16px;
  padding: 20px;
  width: 480px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.episode-header {
  display: flex;
  flex-direction: row;
  gap: 14px;
  align-items: flex-start;
}

.podcast-art {
  width: 76px;
  height: 76px;
  min-width: 76px;
  background: var(--bg-art);
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.art-inner {
  width: 52px;
  height: 52px;
  background: var(--bg-art-inner);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
}

.art-circle {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  border: 3px solid var(--art-circle);
  position: absolute;
}

.art-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: var(--art-dot);
  border: 2px solid var(--art-circle);
  position: relative;
  z-index: 1;
}

.episode-meta {
  display: flex;
  flex-direction: column;
  gap: 4px;
  flex: 1;
}

.podcast-name {
  font-size: 11px;
  font-weight: 600;
  color: var(--accent);
  text-transform: uppercase;
  letter-spacing: 1px;
}

.episode-title {
  font-size: 16px;
  font-weight: 700;
  color: var(--text-primary);
  margin: 0;
  line-height: 1.3;
}

.episode-tags {
  display: flex;
  flex-direction: row;
  gap: 6px;
  flex-wrap: wrap;
  margin-top: 2px;
}

.tag {
  background: var(--tag-bg);
  color: var(--tag-text);
  font-size: 11px;
  font-weight: 500;
  padding: 3px 8px;
  border-radius: 20px;
}

.progress-section {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.progress-bar {
  width: 100%;
  height: 6px;
  background: var(--progress-track);
  border-radius: 3px;
  position: relative;
}

.progress-fill {
  width: 42%;
  height: 100%;
  background: var(--progress-fill);
  border-radius: 3px;
  position: absolute;
  top: 0;
  left: 0;
}

.progress-thumb {
  width: 14px;
  height: 14px;
  background: var(--progress-thumb);
  border-radius: 50%;
  position: absolute;
  top: 50%;
  left: 42%;
  transform: translate(-50%, -50%);
}

.time-row {
  display: flex;
  flex-direction: row;
  justify-content: space-between;
}

.time-current {
  font-size: 12px;
  font-weight: 600;
  color: var(--accent);
}

.time-total {
  font-size: 12px;
  font-weight: 500;
  color: var(--text-muted);
}

.controls-row {
  display: flex;
  flex-direction: row;
  justify-content: center;
  align-items: center;
  gap: 10px;
}

.ctrl-btn {
  background: var(--ctrl-bg);
  color: var(--ctrl-text);
  border: none;
  border-radius: 10px;
  padding: 10px 14px;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  line-height: 1;
}

.ctrl-btn.play {
  background: var(--play-bg);
  color: var(--play-text);
  border-radius: 50%;
  width: 48px;
  height: 48px;
  font-size: 16px;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: center;
}

.info-row {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 8px;
}

.info-item {
  background: var(--info-bg);
  border: 1px solid var(--info-border);
  border-radius: 10px;
  padding: 8px 6px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
}

.info-label {
  font-size: 10px;
  font-weight: 500;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.info-value {
  font-size: 13px;
  font-weight: 700;
  color: var(--text-primary);
}
